// packages/core/src/build/bundler.js

import fs from "fs"
import path from "path"

function readFileSafe(filePath) {

  try {
    return fs.readFileSync(filePath, "utf8")
  } catch {
    return ""
  }

}

export async function bundleModules(projectFiles) {

  const { source, modules } = projectFiles

  let bundle = ""

  bundle += "// Najumi Production Bundle\n"
  bundle += "// Generated by Najumi Build System\n\n"

  // bundle source files
  for (const file of source) {

    const code = readFileSafe(file)

    bundle += "\n"
    bundle += `// File: ${file}\n`
    bundle += code
    bundle += "\n"

  }

  // bundle module files
  for (const file of modules) {

    const code = readFileSafe(file)

    bundle += "\n"
    bundle += `// Module: ${file}\n`
    bundle += code
    bundle += "\n"

  }

  return bundle

}